const items = $input.all();
const pick = (...vals) => {
  for (const v of vals) {
    if (v === null || v === undefined) continue;
    const s = String(v).trim();
    if (s) return s;
  }
  return null;
};
const out = [];
for (const it of items) {
  const j = it.json || {};
  const env = (j.body && typeof j.body === 'object') ? j.body : j;
  const lead = (env.lead && typeof env.lead === 'object') ? env.lead : env;
  out.push({ json: { __lead: {
    source: pick(lead.source, env.source),
    external_id: pick(lead.external_id, env.external_id, env.id),
    url: pick(lead.url, env.url),
    title: pick(lead.title, env.title),
    body: pick(lead.body, env.body, env.message),
    author: pick(lead.author, env.author),
    posted_at: pick(lead.posted_at, env.posted_at, env.created_at),
  } } });
}
return out;

const readSecret = (k) => {
  let v = null;
  try { v = $env[k]; } catch (e) {}
  if (v === null || v === undefined || v === '') {
    try { v = typeof $vars !== 'undefined' ? $vars[k] : null; } catch (e) {}
  }
  return (v === null || v === undefined) ? '' : String(v);
};
const CAP = Number(readSecret("DIRNOTIF_LLM_DAILY_BUDGET_USD"));
const capOk = Number.isFinite(CAP);
const s = $getWorkflowStaticData('global');
const today = new Date().toISOString().slice(0, 10);
if (s.dirnotif_spend_day !== today) { s.dirnotif_spend_day = today; s.dirnotif_spend_usd = 0; }
const items = $input.all();
// n8n Cloud freezes Code-node input items (IN-25): RETURN new items so the spend
// gate reads __spend_ok and Clamp reads __t0.
return items.map((it) => {
  const item = { json: Object.assign({}, it.json, {
    // Fail closed: no reachable numeric cap => spend NOT ok.
    __spend_ok: capOk && (Number(s.dirnotif_spend_usd) || 0) < CAP,
    __t0: Date.now(),
  }) };
  if (it.binary) item.binary = it.binary;
  return item;
});

