const LEAD_TYPES = ['hiring', 'asking_for_help', 'evaluating_tools', 'showcasing', 'discussion', 'off_topic'];
const BUDGETS = ['none', 'low', 'med', 'high'];
const URGENCIES = ['low', 'med', 'high'];
const MODEL = "anthropic/claude-haiku-4-5";
const MAX = 280;
const s = $getWorkflowStaticData('global');
const ctxItems = $('Spend Check').all();
const items = $input.all();
const out = [];
const NULL_SCORES = {
  is_relevant: null, lead_type: null, fit_score: null, intent_score: null,
  actionability_score: null, budget_signal: null, urgency: null, category: null,
  why: null, suggested_angle: null, confidence: null,
};
for (let i = 0; i < items.length; i++) {
  const resp = items[i].json || {};
  const c = (ctxItems[i] || ctxItems[0] || { json: {} }).json;
  const now = new Date().toISOString();
  const status = Number(resp.statusCode || 0);
  // Hosted n8n Cloud hands JSON content-type bodies back PRE-PARSED as objects
  // (LIVE-PROVEN 2026-07-07). Parse OBJECT-FIRST; keep the failure-trace branches.
  const rawBody = resp.body;
  const bodyEmpty = !(rawBody && typeof rawBody === 'object') && !String(rawBody ?? '').trim();
  const parsed = (function(__b){ if (__b && typeof __b === 'object') return __b; const __s = String(__b ?? '').trim(); if (!__s) return null; try { return JSON.parse(__s); } catch (__e) { return null; } })(rawBody);
  const usage = (parsed && parsed.usage) || {};
  const tokensIn = Number(usage.prompt_tokens || 0);
  const tokensOut = Number(usage.completion_tokens || 0);
  const cost = (tokensIn + tokensOut) / 1e6; // coarse estimate; studio reconciles out of band
  s.dirnotif_spend_usd = (Number(s.dirnotif_spend_usd) || 0) + cost;
  const latency = Date.now() - Number(c.__t0 || Date.now());
  const fail = (reason) => Object.assign({}, NULL_SCORES, { enriched: false, reason: reason, attempted_at: now });
  const clampInt = (x) => { const n = Math.round(Number(x)); return Number.isFinite(n) ? Math.min(5, Math.max(0, n)) : 0; };
  const str = (x, n) => (typeof x === 'string' && x.trim()) ? x.slice(0, n) : null;

  let e;
  if (bodyEmpty) {
    e = fail('llm_timeout');
  } else if (status < 200 || status >= 300) {
    e = fail('llm_error');
  } else if (!parsed) {
    e = fail('parse_error');
  } else {
    const content = parsed.choices && parsed.choices[0]
      && parsed.choices[0].message && parsed.choices[0].message.content;
    let v = null;
    if (typeof content === 'string') {
      const stripped = content.replace(/^\s*```[a-z]*\s*/i, '').replace(/\s*```\s*$/, '');
      try { v = JSON.parse(stripped); } catch (e2) { v = null; }
    } else if (content && typeof content === 'object') {
      v = content;
    }
    if (!v || typeof v !== 'object') {
      e = fail('parse_error');
    } else if (!LEAD_TYPES.includes(v.lead_type)) {
      e = fail('validation_error');
    } else {
      let conf = Number(v.confidence);
      if (!Number.isFinite(conf)) conf = 0;
      conf = Math.min(1, Math.max(0, conf));
      e = {
        enriched: true,
        is_relevant: v.is_relevant === true,
        lead_type: v.lead_type,
        fit_score: clampInt(v.fit_score),
        intent_score: clampInt(v.intent_score),
        actionability_score: clampInt(v.actionability_score),
        budget_signal: BUDGETS.includes(v.budget_signal) ? v.budget_signal : 'none',
        urgency: URGENCIES.includes(v.urgency) ? v.urgency : 'low',
        category: str(v.category, 80),
        why: str(v.why, MAX),
        suggested_angle: str(v.suggested_angle, MAX),
        confidence: conf,
        model: MODEL,
        tokens_in: tokensIn,
        tokens_out: tokensOut,
        cost_usd: cost,
        latency_ms: latency,
        enriched_at: now,
      };
    }
  }
  out.push({ json: e });
}
return out;

const NULL_SCORES = {
  is_relevant: null, lead_type: null, fit_score: null, intent_score: null,
  actionability_score: null, budget_signal: null, urgency: null, category: null,
  why: null, suggested_angle: null, confidence: null,
};
const now = new Date().toISOString();
return $input.all().map(() => ({ json:
  Object.assign({}, NULL_SCORES, { enriched: false, reason: 'spend_cap', attempted_at: now }) }));
